const WeatherCard = ({
  city,
  icon,
  temperature,
  feelsLike,
  condition,
  wind,
  humidity,
  aqi
}) => {

  const getAQILabel = (value) => {
  value = Number(value); // important
  if (value === 1) return "Good";
  if (value === 2) return "Moderate";
  if (value === 3) return "Unhealthy (Sensitive)";
  if (value === 4) return "Unhealthy";
  if (value === 5) return "Very Unhealthy";
  return "Hazardous";
};
  const getAQIColor = (value) => {
  value = Number(value); //  important
  if (value === 1) return "#00e400";
  if (value === 2) return "#ffff00";
  if (value === 3) return "#ff7e00";
  if (value === 4) return "#ff0000";
  if (value === 5) return "#8f3f97";
  return "#7e0023";
};

  return (
    <div className="card">
      <h2>{city}</h2>
      <img src={icon} alt="weather icon" />
      <p>{temperature}</p>
      <p>{feelsLike}</p>
      <p>{condition}</p>
      <p>{wind}</p>
      <p>{humidity}</p>

      {/* AQI BOX */}
      <div
  style={{
    backgroundColor: getAQIColor(aqi),
    padding: "10px",
    borderRadius: "8px",
    marginTop: "10px",
    color: "#000",
    fontWeight: "bold"
  }}
>
  AQI: {aqi || "N/A"} {aqi ? `— ${getAQILabel(aqi)}` : ""}
</div>
    </div>
  );
};



export default WeatherCard;
